  card_summary = 'High-Bar Back Squat is a barbell strength exercise for heavy bilateral force production with a more upright torso and high lower-body loading ceiling. Use it when the training goal is force production, tissue capacity, and repeatable positions—not conditioning volume.',
  coach_language = 'Primary subrole: Squat / Knee-Dominant Strength. Score Strength high. Explosiveness can receive secondary credit only when the delivery uses crisp intent, appropriate load, and full recovery without changing this into Output or conditioning.',
  athlete_language = 'Set your body first, move the bar with control, and make every rep look repeatable. Strong and sharp beats heavy and sloppy.',
  movement_family = 'Barbell squat strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'barbell_squat_strength',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = 30,
  default_rest_seconds = 120,
  est_seconds_per_set = 150,
