  coaching_execution = '{"movement_description":"Coach High-Bar Back Squat as a strength-focused barbell pattern with deliberate setup, controlled range, and clean reset between reps.","setup":["Set the rack, bench, box, blocks, or bar height so the athlete can start and finish safely.","Load the bar conservatively for the athlete''s current pattern quality.","Establish stance, grip, brace, and eye line before the first rep.","Confirm the athlete has a clear re-rack, set-down, or bail plan."],"execution_steps":["Brace before the bar moves.","Move through the athlete''s controllable range without chasing extra depth or range.","Keep the bar path consistent and the working joints aligned.","Finish the rep under control, reset breath and brace, then repeat."],"coach_cues":["Brace first.","Own the bar path.","Push the floor away.","Same rep every rep.","Stop before the rep gets ugly."],"breathing_cues":["Inhale and brace before the effort.","Exhale through the sticking point or reset at the top as appropriate.","Do not let breath-holding hide poor position."],"common_faults":["Adding load before the setup is repeatable.","Rushing the eccentric or losing position at end range.","Turning a strength lift into a conditioning set.","Grinding through pain, dizziness, or obvious compensation."],"quality_gate":["Bar path stays consistent.","No pain or joint collapse.","Athlete can repeat the same rep at the planned RPE.","Coach would be comfortable adding small load next week."],"stop_signs":["Pain appears or changes the pattern.","Bar speed slows into a technical grind.","Athlete loses brace, alignment, or safe rack/set-down control.","Dizziness, nausea, or panic breathing appears."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Accessory strength","Resilience work","Sustained capacity only if technique remains safe"],"pairs_well_after":["General warmup","Pattern-specific mobility","Low-volume output or sprint/jump work when used in the same session"],"good_for_sessions":["lower_body_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["No safe equipment setup or supervision for the athlete''s level.","Pain appears in the loaded pattern.","The session priority is fresh speed or jump output and the athlete is already fatigued.","The coach plans to use it as a burnout conditioning station."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex barbell strength demo recommended","NSCA-style resistance training technique standards"],"internal_notes":["Strength score: 5/5. Explosiveness delivery potential: 2/5; only score it when reps are crisp, rested, and intent-driven.","Film at least one side angle and one front/45-degree angle for bar path and alignment."]}'::jsonb,
  updated_at = now()
WHERE slug = 'high-bar-back-squat';

