  description = 'Dumbbell Incline Press is a dumbbell-loaded strength exercise for upper-body pressing force. Load, range, tempo, and rest should support force production rather than metabolic fatigue.',
  card_summary = 'Incline pressing variation that builds upper-chest and shoulder strength while preserving independent-arm control. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.',
  coach_language = 'Primary subrole: Upper-body push strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.',
  athlete_language = 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.',
  movement_family = 'Upper-Body Push Strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'upper_body_push_strength',
  primary_order_slot = 'dumbbell_incline_press_strength',
  default_sets = 3,
  default_reps = 8,
  default_work_seconds = 40,
  default_rest_seconds = 90,
  est_seconds_per_set = 130,
  movement_requirements = '{"primary_joint_actions":["incline_press","shoulder_flexion_adduction","elbow_extension","bracing"],"primary_tissues":["upper_pectorals","anterior_deltoids","triceps"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"stable","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Dumbbell Incline Press: Incline pressing variation that builds upper-chest and shoulder strength while preserving independent-arm control. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select dumbbells that can be pressed without joint compensation for Dumbbell Incline Press.","Set the shoulder blades and grip before the first rep.","Brace ribs over pelvis; avoid flaring to create false range.","Begin from a stable floor, bench, kneeling, seated, or standing setup as the variation requires."],"execution_steps":["Press the dumbbells through the prescribed path without shrugging or rib flare.","Control the lowering phase and keep elbows tracking naturally.","Finish each rep with joints stacked and shoulders stable.","Pause or reset when speed or line changes."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"athlete_cues":["Set your body first.","Move the weight, not your joints.","Strong and smooth.","Leave one clean rep in reserve."],"breathing_cues":["Inhale before the lowering or reset.","Brace through the hard portion.","Exhale without collapsing posture."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Ribs flare or shoulders shrug to finish the press."],"quality_gate":["No pain.","Start and finish positions match.","Load path is repeatable.","Final rep looks close to the first rep."],"stop_signs":["Pain appears or increases during the set.","Technique changes more than one rep in a row.","Breathing becomes dizziness, bracing panic, or uncontrolled breath holding.","Grip, shoulder, spine, hip, knee, or ankle position becomes unsafe."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Low-skill accessory strength","Core or carry work","Conditioning placed later if movement quality remains high"],"pairs_well_after":["General warm-up","Mobility access for the target joints","Low-fatigue activation or pattern rehearsal"],"good_for_sessions":["overhead_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears in the loaded pattern.","Athlete cannot control the dumbbells safely.","Grip or posture fails before the target tissues are trained.","The session needs true max-speed or jump Output and this would create fatigue first."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex dumbbell strength demo recommended","NSCA-style resistance training exercise technique standards","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules"],"internal_notes":["Film Dumbbell Incline Press from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics."]}'::jsonb,
  updated_at = now()
WHERE slug = 'dumbbell-incline-press';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'dumbbell_incline_press_strength',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 3,
  fatigue_cost = 3,
  technical_complexity = 2,
  impact_level = 0,
  intensity_ceiling = 'high',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'dumbbell_incline_press_strength' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'dumbbell-incline-press';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'reps',
  default_sets = 3,
  default_reps = 8,
  default_distance = NULL::integer,
  default_work_seconds = 40,
  default_rest_seconds = 90,
  est_seconds_per_set = 130,
  default_rpe_min = 6,
  default_rpe_max = 8,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'dumbbell-incline-press';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = 3,
  minimum_hours_between_hard_exposures = 24,
  counts_as_high_intensity = TRUE,
  counts_as_high_impact = FALSE,
  counts_as_neural = TRUE,
  counts_as_tissue_stress = TRUE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'dumbbell-incline-press';

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 2,
  impact_level = 0,
  requires_spotting = FALSE,
  requires_coach_supervision = 'recommended',
  readiness_checks = ARRAY['Athlete can demonstrate the unloaded pattern without pain.', 'Athlete can brace and breathe without dizziness.', 'Athlete can stop the set before technique deteriorates.']::text[],
  contraindications = ARRAY['Painful joint loading in the pattern.', 'Uncontrolled spine, shoulder, hip, knee, ankle, or wrist position.', 'No safe space or support for the variation.']::text[],
  common_substitutions = ARRAY['Push-up variation', 'Dumbbell floor press', 'Half-kneeling press regression']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'dumbbell-incline-press';

