);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and force/tissue capacity for loaded strength in the Capacity phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('high-bar-back-squat', 'The barbell provides a scalable external resistance that forces the athlete to organize posture, brace, produce force, and control the loaded path. For High-Bar Back Squat, the main adaptation is strength: higher force capacity, tissue tolerance, and repeatable joint positions.', 'Belongs in Capacity because the primary adaptation is loaded force development. Place after high-skill or true power work so fatigue from heavy strength does not steal speed, jumping, or movement quality.', 'Capacity phase after Prepare & Access, Movement Intelligence, and any true Output work. It can support explosiveness when coached with high intent and full rest, but it should not be programmed as a fatigue-based plyometric or conditioning station.', 'Do not chase load, fatigue, or bar speed after technique breaks. Do not tag or program this primarily as explosiveness unless the delivery is deliberately low-volume, high-intent, and fully recovered.', 'Scale by load, range of motion, tempo, stance, support, and rest before adding complexity. Progress only when posture, breathing, and bar path are repeatable.'),
